      ctx.beginPath();
      ctx.moveTo(cx - w / 2, cy);
      ctx.lineTo(cx - w * 0.28, cy - h / 2);
      ctx.lineTo(cx + w * 0.28, cy - h / 2);
      ctx.lineTo(cx + w / 2, cy);
      ctx.lineTo(cx + w * 0.28, cy + h / 2);
      ctx.lineTo(cx - w * 0.28, cy + h / 2);
      ctx.closePath();
      ctx.fillStyle = config.fill || theme.frameDeep;
      ctx.strokeStyle = config.stroke || theme.gold;
      ctx.lineWidth = 1.2;
      ctx.fill();
      ctx.stroke();
      ctx.shadowBlur = 0;
      ctx.strokeStyle = config.highlight || theme.goldBright;
      ctx.globalAlpha = 0.72;
      ctx.beginPath();
      ctx.moveTo(cx - w * 0.24, cy - h * 0.28);
      ctx.lineTo(cx + w * 0.24, cy - h * 0.28);
      ctx.moveTo(cx - w * 0.24, cy + h * 0.28);
      ctx.lineTo(cx + w * 0.24, cy + h * 0.28);
      ctx.stroke();
      ctx.restore();
      if (config.gem === false) return;
